@page "/chat"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@using Microsoft.JSInterop
@attribute [Authorize]
@using LiftAI.App.Components.Chat
@using LiftAI.App.Services
@using LiftAI.Shared.Models.Dtos.Chat
@using LiftAI.Shared.Models.Dtos.Conversation
@using LiftAI.Shared.Models.Enums
@inject ChatService ChatService
@inject ChatHistoryState ChatHistoryState
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>AI Chat</PageTitle>

<AuthorizeView>
    <Authorized>
        <div class="chat-shell">
            <aside class="chat-panel @(isPanelOpen ? "is-open" : "")">
                <ConversationList IsVisible="isPanelOpen" IsVisibleChanged="TogglePanel" />
            </aside>
            <div class="chat-overlay @(isPanelOpen ? "is-visible" : "")" @onclick="ClosePanel"></div>

            <section class="chat-main">
                <header class="chat-header">
                    <button type="button" class="chat-panel-toggle" @onclick="TogglePanel" aria-label="Toggle conversations">
                        Chats
                    </button>
                    <div class="chat-header__titles">
                        <div class="chat-header__title">AI Coach</div>
                        <div class="chat-header__subtitle">Ask about workouts, recovery, or nutrition</div>
                    </div>
                    <button type="button" class="chat-new-button" @onclick="StartNewConversation" aria-label="New conversation">
                        New
                    </button>
                </header>

                <div class="chat-messages">
                    @if (!string.IsNullOrWhiteSpace(errorMessage))
                    {
                        <div class="chat-error">@errorMessage</div>
                    }

                    @if (SelectedConversation is null)
                    {
                        <div class="chat-empty">Select a chat or start a new one.</div>
                    }
                    else if (SelectedConversation.Messages.Count == 0)
                    {
                        <div class="chat-empty">No messages yet. Say hello to start!</div>
                        <div class="chat-suggestions">
                            <button class="chat-suggestion" @onclick='() => SetPrompt("Build me a 3-day workout split")'>3-day workout split</button>
                            <button class="chat-suggestion" @onclick='() => SetPrompt("How should I warm up for leg day?")'>Leg day warm-up</button>
                            <button class="chat-suggestion" @onclick='() => SetPrompt("What should I eat post-workout?")'>Post-workout meals</button>
                        </div>
                    }
                    else
                    {
                        foreach (var message in SelectedConversation.Messages)
                        {
                            <div class="chat-message @(message.Role == ChatRole.User ? "user-message" : "assistant-message")">
                                @message.Content
                            </div>
                        }
                    }

                    @if (isSending)
                    {
                        <div class="chat-message assistant-message chat-typing">Assistant is typing...</div>
                    }

                    <div class="chat-scroll-anchor" aria-hidden="true"></div>
                </div>

                <form class="chat-input-container" @onsubmit="SendMessageAsync" @onsubmit:preventDefault="true">
                    <div class="chat-effort">
                        <button type="button"
                                class="effort-toggle"
                                aria-expanded="@isEffortMenuOpen"
                                @onclick="ToggleEffortMenu">
                            <span class="effort-label">@EffortLabel</span>
                            <i class="bi bi-chevron-down" aria-hidden="true"></i>
                        </button>
                        <div class="effort-menu @(isEffortMenuOpen ? "is-open" : "")" role="menu">
                            <button type="button"
                                    class="effort-option @(contextMode == ContextMode.Normal ? "is-active" : "")"
                                    @onclick="() => SetContextMode(ContextMode.Normal)">
                                Normal
                            </button>
                            <button type="button"
                                    class="effort-option @(contextMode == ContextMode.Deep ? "is-active" : "")"
                                    @onclick="() => SetContextMode(ContextMode.Deep)">
                                Deep
                            </button>
                        </div>
                    </div>

                    <div class="chat-input-shell">
                        <input class="chat-input" placeholder="Type a message..."
                               @bind-value="currentMessage" @bind-value:event="oninput" />
                        <button class="send-button @(IsSendReady ? "" : "is-disabled")" type="button" @onclick="SendMessageAsync" aria-label="Send message" aria-disabled="@(!IsSendReady)">
                            <i class="bi bi-send" aria-hidden="true"></i>
                        </button>
                    </div>
                </form>
            </section>
        </div>
    </Authorized>
    <NotAuthorized>
        <div class="chat-unauthorized">
            <h2>Sign in required</h2>
            <p>You need to be logged in to use the AI chat.</p>
            <a class="btn btn-primary" href="/login">Go to login</a>
        </div>
    </NotAuthorized>
</AuthorizeView>

@code {
    private string? currentMessage;
    private string? errorMessage;
    private bool isSending;
    private bool isPanelOpen = false;
    private bool isEffortMenuOpen;
    private int lastRenderedMessageCount;
    private ContextMode contextMode = ContextMode.Normal;

    private bool IsSendReady => !isSending && !string.IsNullOrWhiteSpace(currentMessage);

    private string EffortLabel => contextMode == ContextMode.Normal ? "Normal" : "Deep";

    private ChatConversationDetailDto? SelectedConversation => ChatHistoryState.SelectedConversation;

    protected override async Task OnInitializedAsync()
    {
        ChatHistoryState.SelectedConversationChanged += OnSelectedConversationChanged;
        await ChatHistoryState.LoadConversationsAsync();

        if (ChatHistoryState.SelectedConversation is null)
        {
            ChatHistoryState.StartNewConversation();
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await JS.InvokeVoidAsync("chatUi.setBodyScrollLock", isPanelOpen);
        }

        var messageCount = SelectedConversation?.Messages.Count ?? 0;
        if (firstRender || messageCount != lastRenderedMessageCount)
        {
            await JS.InvokeVoidAsync("chatUi.scrollToBottomIfNearBottom", ".chat-messages", 140);
            lastRenderedMessageCount = messageCount;
        }
    }

    private void OnSelectedConversationChanged(object? sender, EventArgs e)
    {
        _ = InvokeAsync(StateHasChanged);
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(currentMessage) || isSending)
        {
            return;
        }

        if (SelectedConversation is null)
        {
            ChatHistoryState.StartNewConversation();
        }

        if (SelectedConversation is null)
        {
            return;
        }

        isSending = true;
        errorMessage = null;
        var userMessage = new ChatMessageDto { Role = ChatRole.User, Content = currentMessage.Trim() };
        SelectedConversation.Messages.Add(userMessage);
        currentMessage = string.Empty;
        await InvokeAsync(StateHasChanged);

        var response = await ChatService.SendMessageAsync(
            SelectedConversation.Id == 0 ? null : SelectedConversation.Id,
            SelectedConversation.Messages,
            contextMode);

        if (response?.Success == true && !string.IsNullOrWhiteSpace(response.Response))
        {
            SelectedConversation.Messages.Add(new ChatMessageDto
            {
                Role = ChatRole.Assistant,
                Content = response.Response
            });

            await ChatHistoryState.RefreshConversationsAsync(response.ConversationId);
        }
        else
        {
            errorMessage = response?.Message ?? "No response received. Please try again.";
        }

        isSending = false;
        await InvokeAsync(StateHasChanged);
    }

    private void ToggleEffortMenu()
    {
        isEffortMenuOpen = !isEffortMenuOpen;
    }

    private async Task TogglePanel()
    {
        isPanelOpen = !isPanelOpen;
        await JS.InvokeVoidAsync("chatUi.setBodyScrollLock", isPanelOpen);
    }

    private async Task ClosePanel()
    {
        if (!isPanelOpen)
        {
            return;
        }

        isPanelOpen = false;
        await JS.InvokeVoidAsync("chatUi.setBodyScrollLock", false);
    }

    private void SetPrompt(string prompt)
    {
        currentMessage = prompt;
    }

    private void SetContextMode(ContextMode mode)
    {
        contextMode = mode;
        isEffortMenuOpen = false;
    }

    private void StartNewConversation()
    {
        ChatHistoryState.StartNewConversation();
    }

    public async ValueTask DisposeAsync()
    {
        ChatHistoryState.SelectedConversationChanged -= OnSelectedConversationChanged;
        await JS.InvokeVoidAsync("chatUi.setBodyScrollLock", false);
    }
}

@page "/chat"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@using Microsoft.JSInterop
@attribute [Authorize]
@using LiftAI.App.Components.Chat
@using LiftAI.App.Services
@using LiftAI.Shared.Models.Dtos.Chat
@using LiftAI.Shared.Models.Dtos.Conversation
@using LiftAI.Shared.Models.Enums
@inject ChatService ChatService
@inject ChatHistoryState ChatHistoryState
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>AI Chat</PageTitle>

<AuthorizeView>
    <Authorized>
        <div class="chat-shell">
            <aside class="chat-panel @(isPanelOpen ? "is-open" : "")">
                <ConversationList IsVisible="isPanelOpen" IsVisibleChanged="TogglePanel" />
            </aside>
            <div class="chat-overlay @(isPanelOpen ? "is-visible" : "")" @onclick="ClosePanel"></div>

            <section class="chat-main">
                <header class="chat-header">
                    <button type="button" class="chat-panel-toggle" @onclick="TogglePanel" aria-label="Toggle conversations">
                        Chats
                    </button>
                    <div class="chat-header__titles">
                        <div class="chat-header__title">AI Coach</div>
                        <div class="chat-header__subtitle">Ask about workouts, recovery, or nutrition</div>
                    </div>
                    <button type="button" class="chat-new-button" @onclick="StartNewConversation" aria-label="New conversation">
                        New
                    </button>
                </header>

                <div class="chat-messages">
                    @if (!string.IsNullOrWhiteSpace(errorMessage))
                    {
                        <div class="chat-error">@errorMessage</div>
                    }

                    @if (SelectedConversation is null)
                    {
                        <div class="chat-empty">Select a chat or start a new one.</div>
                    }
                    else if (SelectedConversation.Messages.Count == 0)
                    {
                        <div class="chat-empty">No messages yet. Say hello to start!</div>
                        <div class="chat-suggestions">
                            <button class="chat-suggestion" @onclick='() => SetPrompt("Build me a 3-day workout split")'>3-day workout split</button>
                            <button class="chat-suggestion" @onclick='() => SetPrompt("How should I warm up for leg day?")'>Leg day warm-up</button>
                            <button class="chat-suggestion" @onclick='() => SetPrompt("What should I eat post-workout?")'>Post-workout meals</button>
                        </div>
                    }
                    else
                    {
                        foreach (var message in SelectedConversation.Messages)
                        {
                            <div class="chat-message @(message.Role == ChatRole.User ? "user-message" : "assistant-message")">
                                @message.Content
                            </div>
                        }
                    }

                    @if (isSending)
                    {
                        <div class="chat-message assistant-message chat-typing">Assistant is typing...</div>
                    }

                    <div class="chat-scroll-anchor" aria-hidden="true"></div>
                </div>

                <form class="chat-input-container @(IsInputDisabled ? "is-disabled" : "")" @onsubmit="SendMessageAsync" @onsubmit:preventDefault="true">
                    <div class="chat-effort">
                        <button type="button"
                                class="effort-toggle"
                                aria-expanded="@isEffortMenuOpen"
                                @onclick="ToggleEffortMenu">
                            <span class="effort-label">@EffortLabel</span>
                            <i class="bi bi-chevron-down" aria-hidden="true"></i>
                        </button>
                        <div class="effort-menu @(isEffortMenuOpen ? "is-open" : "")" role="menu">
                            <button type="button"
                                    class="effort-option @(contextMode == ContextMode.Normal ? "is-active" : "")"
                                    @onclick="() => SetContextMode(ContextMode.Normal)">
                                Normal
                            </button>
                            <div class="effort-option-wrapper" data-tooltip="Premium only" aria-hidden="@isPremium">
                                <button type="button"
                                        class="effort-option @(contextMode == ContextMode.Deep ? "is-active" : "")"
                                        disabled="@(!isPremium)"
                                        aria-disabled="@(!isPremium)"
                                        @onclick="() => SetContextMode(ContextMode.Deep)">
                                    Deep
                                </button>
                            </div>
                        </div>
                    </div>

                    <div class="chat-input-shell @(IsInputDisabled ? "is-disabled" : "")">
                        <input class="chat-input" placeholder="Type a message..."
                               disabled="@IsInputDisabled"
                               @bind-value="currentMessage" @bind-value:event="oninput" />
                        <button class="send-button @(IsSendReady ? "" : "is-disabled")"
                                type="button"
                                disabled="@(!IsSendReady)"
                                @onclick="SendMessageAsync"
                                aria-label="Send message"
                                aria-disabled="@(!IsSendReady)">
                            <i class="bi bi-send" aria-hidden="true"></i>
                        </button>
                    </div>
                </form>

                @if (RemainingRequestsToday == 1)
                {
                    <div class="chat-quota-note">This is your last remaining message left today.</div>
                }

                @if (isQuotaLimited)
                {
                    <div class="chat-quota-note chat-quota-note--limit">Daily chat limit reached. Try again tomorrow.</div>
                }
            </section>
        </div>
    </Authorized>
    <NotAuthorized>
        <div class="chat-unauthorized">
            <h2>Sign in required</h2>
            <p>You need to be logged in to use the AI chat.</p>
            <a class="btn btn-primary" href="/login">Go to login</a>
        </div>
    </NotAuthorized>
</AuthorizeView>

@code {
    private string? currentMessage;
    private string? errorMessage;
    private bool isSending;
    private bool isPanelOpen = false;
    private bool isEffortMenuOpen;
    private int lastRenderedMessageCount;
    private ContextMode contextMode = ContextMode.Normal;
    private bool isPremium;
    private bool isQuotaLimited;
    private bool isQuotaLoading = true;
    private int? remainingRequestsToday;

    private bool IsInputDisabled => isQuotaLoading || isQuotaLimited;

    private bool IsSendReady => !isSending && !IsInputDisabled && !string.IsNullOrWhiteSpace(currentMessage);

    private int? RemainingRequestsToday => isPremium ? null : remainingRequestsToday;

    private string EffortLabel => contextMode == ContextMode.Normal ? "Normal" : "Deep";

    private ChatConversationDetailDto? SelectedConversation => ChatHistoryState.SelectedConversation;

    protected override async Task OnInitializedAsync()
    {
        ChatHistoryState.SelectedConversationChanged += OnSelectedConversationChanged;
        await ChatHistoryState.LoadConversationsAsync();
        await LoadQuotaStatusAsync();

        if (ChatHistoryState.SelectedConversation is null)
        {
            ChatHistoryState.StartNewConversation();
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await JS.InvokeVoidAsync("chatUi.setBodyScrollLock", isPanelOpen);
        }

        var messageCount = SelectedConversation?.Messages.Count ?? 0;
        if (firstRender || messageCount != lastRenderedMessageCount)
        {
            await JS.InvokeVoidAsync("chatUi.scrollToBottomIfNearBottom", ".chat-messages", 140);
            lastRenderedMessageCount = messageCount;
        }
    }

    private void OnSelectedConversationChanged(object? sender, EventArgs e)
    {
        _ = InvokeAsync(StateHasChanged);
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(currentMessage) || isSending || IsInputDisabled)
        {
            return;
        }

        if (SelectedConversation is null)
        {
            ChatHistoryState.StartNewConversation();
        }

        if (SelectedConversation is null)
        {
            return;
        }

        isSending = true;
        errorMessage = null;
        var userMessage = new ChatMessageDto { Role = ChatRole.User, Content = currentMessage.Trim() };
        SelectedConversation.Messages.Add(userMessage);
        currentMessage = string.Empty;
        await InvokeAsync(StateHasChanged);

        var response = await ChatService.SendMessageAsync(
            SelectedConversation.Id == 0 ? null : SelectedConversation.Id,
            SelectedConversation.Messages,
            contextMode);

        if (response?.Success == true && !string.IsNullOrWhiteSpace(response.Response))
        {
            SelectedConversation.Messages.Add(new ChatMessageDto
            {
                Role = ChatRole.Assistant,
                Content = response.Response
            });

            await ChatHistoryState.RefreshConversationsAsync(response.ConversationId);
            remainingRequestsToday = response.RemainingRequestsToday;
        }
        else
        {
            errorMessage = response?.Message ?? "No response received. Please try again.";
        }

        if (response?.IsQuotaLimited == true)
        {
            await LoadQuotaStatusAsync();
        }

        isSending = false;
        await InvokeAsync(StateHasChanged);
    }

    private async Task LoadQuotaStatusAsync()
    {
        isQuotaLoading = true;
        await InvokeAsync(StateHasChanged);

        var status = await ChatService.GetQuotaStatusAsync();
        if (status is not null)
        {
            isPremium = status.IsPremium;
            isQuotaLimited = status.IsQuotaLimited;
            remainingRequestsToday = status.RemainingRequestsToday;
        }

        isQuotaLoading = false;
    }

    private void ToggleEffortMenu()
    {
        isEffortMenuOpen = !isEffortMenuOpen;
    }

    private async Task TogglePanel()
    {
        isPanelOpen = !isPanelOpen;
        await JS.InvokeVoidAsync("chatUi.setBodyScrollLock", isPanelOpen);
    }

    private async Task ClosePanel()
    {
        if (!isPanelOpen)
        {
            return;
        }

        isPanelOpen = false;
        await JS.InvokeVoidAsync("chatUi.setBodyScrollLock", false);
    }

    private void SetPrompt(string prompt)
    {
        currentMessage = prompt;
    }

    private void SetContextMode(ContextMode mode)
    {
        if (mode == ContextMode.Deep && !isPremium)
        {
            return;
        }

        contextMode = mode;
        isEffortMenuOpen = false;
    }

    private void StartNewConversation()
    {
        ChatHistoryState.StartNewConversation();
    }

    public async ValueTask DisposeAsync()
    {
        ChatHistoryState.SelectedConversationChanged -= OnSelectedConversationChanged;
        await JS.InvokeVoidAsync("chatUi.setBodyScrollLock", false);
    }
}

.app-shell__content:has(.chat-shell) {
    max-width: 100%;
    margin: 0;
    padding: 0;
}

.chat-shell {
    display: grid;
    grid-template-columns: 1fr;
    min-height: 100dvh;
    background: var(--app-bg);
    position: relative;
    width: 100%;
}

.chat-overlay {
    position: fixed;
    inset: 0;
    background: rgba(34, 27, 18, 0.35);
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.2s ease;
    z-index: 30;
}

.chat-overlay.is-visible {
    opacity: 1;
    pointer-events: auto;
}

.chat-suggestions {
    margin-top: 1rem;
    display: flex;
    flex-wrap: wrap;
    gap: 0.5rem;
    justify-content: center;
}

.chat-suggestion {
    border: 1px solid var(--app-border-strong);
    background: var(--app-chip);
    color: var(--app-text);
    padding: 0.45rem 0.8rem;
    border-radius: 0.9rem;
    font-weight: 600;
}

.chat-panel {
    position: fixed;
    inset: 0 auto 0 0;
    width: min(86vw, 320px);
    border-right: 1px solid var(--app-border);
    background: var(--app-card);
    overflow: hidden;
    box-shadow: var(--app-shadow);
    transform: translateX(-100%);
    transition: transform var(--app-motion);
    z-index: 40;
    visibility: hidden;
}

.chat-panel.is-open {
    transform: translateX(0);
    visibility: visible;
}

.chat-main {
    display: flex;
    flex-direction: column;
    min-height: 100dvh;
    position: relative;
    padding-bottom: 0;
}

.chat-header {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 1rem 1.4rem;
    border-bottom: 1px solid var(--app-border);
    background: rgba(255, 247, 236, 0.96);
    backdrop-filter: blur(8px);
    z-index: 10;
}

.chat-header__titles {
    flex: 1;
}

.chat-header__title {
    font-weight: 700;
    font-size: 1.1rem;
}

.chat-header__subtitle {
    font-size: 0.85rem;
    color: var(--app-text-soft);
}

.chat-panel-toggle {
    border: 1px solid var(--app-border-strong);
    background: var(--app-chip);
    color: var(--app-text);
    padding: 0.4rem 0.8rem;
    border-radius: 0.85rem;
    font-weight: 600;
}

.chat-new-button {
    border: 1px solid var(--app-border-strong);
    background: var(--app-chip);
    color: var(--app-text);
    padding: 0.4rem 0.85rem;
    border-radius: 0.85rem;
    font-weight: 600;
}

.chat-messages {
    flex: 1;
    overflow-y: auto;
    padding: 1.25rem 1.4rem 1rem;
    display: flex;
    flex-direction: column;
    gap: 0.85rem;
    overscroll-behavior: contain;
}

.chat-empty {
    color: var(--app-text-soft);
    text-align: center;
    margin-top: 2rem;
}

.chat-message {
    padding: 0.8rem 1rem;
    border-radius: 1.1rem;
    max-width: 85%;
    word-break: break-word;
    animation: fade-rise 0.25s ease;
    border: 1px solid var(--app-border);
    background: transparent;
}

.user-message {
    background: rgba(122, 77, 30, 0.12);
    color: var(--app-text);
    align-self: flex-end;
}

.assistant-message {
    background: transparent;
    color: var(--app-text);
    align-self: flex-start;
}

.chat-typing {
    opacity: 0.8;
    font-style: italic;
}

.chat-input-container {
    display: grid;
    grid-template-columns: auto 1fr;
    gap: 0.75rem;
    padding: 0.8rem 1.4rem 0.9rem;
    border-top: 1px solid var(--app-border);
    background: transparent;
    backdrop-filter: none;
    position: static;
    margin: 0 0 4.4rem;
    z-index: 1;
    pointer-events: auto;
}

.chat-effort {
    position: relative;
}

.effort-toggle {
    border: 1px solid var(--app-border-strong);
    background: var(--app-card);
    color: var(--app-text);
    padding: 0.45rem 0.85rem;
    border-radius: 999px;
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
    font-weight: 600;
    box-shadow: var(--app-shadow-soft);
}

.effort-menu {
    position: absolute;
    bottom: calc(100% + 0.5rem);
    left: 0;
    min-width: 140px;
    display: grid;
    gap: 0.4rem;
    padding: 0.6rem;
    border-radius: 0.85rem;
    border: 1px solid var(--app-border);
    background: rgba(22, 18, 13, 0.96);
    box-shadow: var(--app-shadow);
    opacity: 0;
    transform: translateY(6px);
    pointer-events: none;
    transition: opacity 0.15s ease, transform 0.15s ease;
    z-index: 30;
}

.effort-menu.is-open {
    opacity: 1;
    transform: translateY(0);
    pointer-events: auto;
}

.effort-option {
    border: 1px solid var(--app-border);
    background: rgba(255, 255, 255, 0.04);
    color: var(--app-text);
    padding: 0.45rem 0.7rem;
    border-radius: 0.7rem;
    text-align: left;
    font-weight: 600;
}

.effort-option.is-active {
    border-color: var(--app-accent-strong);
    background: var(--app-accent-strong);
    color: #fff;
}

.chat-input-shell {
    display: grid;
    grid-template-columns: 1fr auto;
    align-items: center;
    gap: 0.6rem;
    padding: 0.5rem 0.6rem 0.5rem 1rem;
    border-radius: 999px;
    border: 1px solid var(--app-border-strong);
    background: var(--app-card);
    box-shadow: var(--app-shadow-soft);
    position: relative;
    z-index: 1;
    pointer-events: auto;
}

.chat-input {
    width: 100%;
    border-radius: 1.2rem;
    border: none;
    padding: 0.4rem 0;
    background: transparent;
    color: var(--app-text);
}

.chat-input:focus {
    outline: none;
}

.send-button {
    border: none;
    border-radius: 999px;
    background: var(--app-accent-strong);
    color: #fff;
    font-weight: 600;
    padding: 0.5rem 0.85rem;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    position: relative;
    z-index: 2;
    cursor: pointer;
    pointer-events: auto;
}

.send-button:disabled {
    cursor: not-allowed;
    background: var(--app-border-strong);
}

.send-button.is-disabled {
    opacity: 0.55;
}

.chat-error {
    background: #fdecea;
    border: 1px solid #f5c2c0;
    color: #9b1c1c;
    padding: 0.75rem 1rem;
    border-radius: 0.9rem;
}

.chat-unauthorized {
    max-width: 520px;
    margin: 2.5rem auto;
    text-align: center;
    padding: 1.5rem;
    background: var(--app-card);
    border: 1px solid var(--app-border);
    border-radius: 1.2rem;
    box-shadow: var(--app-shadow-soft);
}

@media (max-width: 960px) {
    .chat-shell {
        padding-bottom: 0;
    }

    .chat-header,
    .chat-input-container {
        margin-left: -0.6rem;
        margin-right: -0.6rem;
        border-radius: 0;
    }

    .chat-panel-toggle {
        display: inline-flex;
    }

    .chat-input-container {
        grid-template-columns: 1fr;
        gap: 0.6rem;
        margin: 0 0 4.4rem;
    }

    .chat-messages {
        padding: 1rem 0.8rem 0.9rem;
    }

    .chat-message {
        max-width: 100%;
    }

    .effort-menu {
        left: 0;
        right: auto;
    }

    .chat-context {
        justify-content: flex-start;
    }
}

@media (min-width: 992px) {
    .chat-shell {
        padding-bottom: 0;
    }

    .chat-panel {
        left: 260px;
        width: min(320px, 30vw);
    }

    .chat-header,
    .chat-input-container {
        border-radius: 999px;
        margin: 1rem 1.8rem 0 0;
    }

    .chat-input-container {
        margin: 1rem 1.8rem 1rem 0;
        bottom: auto;
        left: auto;
        right: auto;
    }

    .chat-messages {
        padding-bottom: 1.6rem;
    }
}

.app-shell__content:has(.chat-shell) {
    max-width: 100%;
    margin: 0;
    padding: 0;
}

.chat-shell {
    display: grid;
    grid-template-columns: 1fr;
    min-height: 100dvh;
    background: var(--app-bg);
    position: relative;
    width: 100%;
}

.chat-overlay {
    position: fixed;
    inset: 0;
    background: rgba(34, 27, 18, 0.35);
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.2s ease;
    z-index: 30;
}

.chat-overlay.is-visible {
    opacity: 1;
    pointer-events: auto;
}

.chat-suggestions {
    margin-top: 1rem;
    display: flex;
    flex-wrap: wrap;
    gap: 0.5rem;
    justify-content: center;
}

.chat-suggestion {
    border: 1px solid var(--app-border-strong);
    background: var(--app-chip);
    color: var(--app-text);
    padding: 0.45rem 0.8rem;
    border-radius: 0.9rem;
    font-weight: 600;
}

.chat-panel {
    position: fixed;
    inset: 0 auto 0 0;
    width: min(86vw, 320px);
    border-right: 1px solid var(--app-border);
    background: var(--app-card);
    overflow: hidden;
    box-shadow: var(--app-shadow);
    transform: translateX(-100%);
    transition: transform var(--app-motion);
    z-index: 40;
    visibility: hidden;
}

.chat-panel.is-open {
    transform: translateX(0);
    visibility: visible;
}

.chat-main {
    display: flex;
    flex-direction: column;
    min-height: 100dvh;
    position: relative;
    padding-bottom: 0;
}

.chat-header {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 1rem 1.4rem;
    border-bottom: 1px solid var(--app-border);
    background: rgba(255, 247, 236, 0.96);
    backdrop-filter: blur(8px);
    z-index: 10;
}

.chat-header__titles {
    flex: 1;
}

.chat-header__title {
    font-weight: 700;
    font-size: 1.1rem;
}

.chat-header__subtitle {
    font-size: 0.85rem;
    color: var(--app-text-soft);
}

.chat-panel-toggle {
    border: 1px solid var(--app-border-strong);
    background: var(--app-chip);
    color: var(--app-text);
    padding: 0.4rem 0.8rem;
    border-radius: 0.85rem;
    font-weight: 600;
}

.chat-new-button {
    border: 1px solid var(--app-border-strong);
    background: var(--app-chip);
    color: var(--app-text);
    padding: 0.4rem 0.85rem;
    border-radius: 0.85rem;
    font-weight: 600;
}

.chat-messages {
    flex: 1;
    overflow-y: auto;
    padding: 1.25rem 1.4rem 1rem;
    display: flex;
    flex-direction: column;
    gap: 0.85rem;
    overscroll-behavior: contain;
}

.chat-empty {
    color: var(--app-text-soft);
    text-align: center;
    margin-top: 2rem;
}

.chat-message {
    padding: 0.8rem 1rem;
    border-radius: 1.1rem;
    max-width: 85%;
    word-break: break-word;
    animation: fade-rise 0.25s ease;
    border: 1px solid var(--app-border);
    background: transparent;
}

.user-message {
    background: rgba(122, 77, 30, 0.12);
    color: var(--app-text);
    align-self: flex-end;
}

.assistant-message {
    background: transparent;
    color: var(--app-text);
    align-self: flex-start;
}

.chat-typing {
    opacity: 0.8;
    font-style: italic;
}

.chat-input-container {
    display: grid;
    grid-template-columns: auto 1fr;
    gap: 0.75rem;
    padding: 0.8rem 1.4rem 0.9rem;
    border-top: 1px solid var(--app-border);
    background: transparent;
    backdrop-filter: none;
    position: static;
    margin: 0 0 4.4rem;
    z-index: 1;
    pointer-events: auto;
}

.chat-input-container.is-disabled {
    opacity: 0.6;
}

.chat-input-shell.is-disabled {
    background: rgba(255, 255, 255, 0.04);
}

.chat-input:disabled {
    cursor: not-allowed;
}

.effort-toggle {
    border: 1px solid var(--app-border-strong);
    background: var(--app-card);
    color: var(--app-text);
    padding: 0.45rem 0.85rem;
    border-radius: 999px;
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
    font-weight: 600;
    box-shadow: var(--app-shadow-soft);
}

.effort-menu {
    position: absolute;
    bottom: calc(100% + 0.5rem);
    left: 0;
    min-width: 140px;
    display: grid;
    gap: 0.4rem;
    padding: 0.6rem;
    border-radius: 0.85rem;
    border: 1px solid var(--app-border);
    background: rgba(22, 18, 13, 0.96);
    box-shadow: var(--app-shadow);
    opacity: 0;
    transform: translateY(6px);
    pointer-events: none;
    transition: opacity 0.15s ease, transform 0.15s ease;
    z-index: 30;
}

.effort-menu.is-open {
    opacity: 1;
    transform: translateY(0);
    pointer-events: auto;
}

.effort-option {
    border: 1px solid var(--app-border);
    background: rgba(255, 255, 255, 0.04);
    color: var(--app-text);
    padding: 0.45rem 0.7rem;
    border-radius: 0.7rem;
    text-align: left;
    font-weight: 600;
}

.effort-option.is-active {
    border-color: var(--app-accent-strong);
    background: var(--app-accent-strong);
    color: #fff;
}

.effort-option-wrapper {
    position: relative;
}

.effort-option-wrapper[aria-hidden="true"]::after {
    content: attr(data-tooltip);
    position: absolute;
    left: 0;
    bottom: calc(100% + 0.4rem);
    background: rgba(20, 16, 12, 0.9);
    color: #fff;
    font-size: 0.7rem;
    padding: 0.25rem 0.45rem;
    border-radius: 0.45rem;
    opacity: 0;
    transform: translateY(4px);
    pointer-events: none;
    transition: opacity 0.12s ease, transform 0.12s ease;
    white-space: nowrap;
}

.effort-option-wrapper[aria-hidden="true"]:hover::after,
.effort-option-wrapper[aria-hidden="true"]:focus-within::after {
    opacity: 1;
    transform: translateY(0);
}

.chat-input-shell {
    display: grid;
    grid-template-columns: 1fr auto;
    align-items: center;
    gap: 0.6rem;
    padding: 0.5rem 0.6rem 0.5rem 1rem;
    border-radius: 999px;
    border: 1px solid var(--app-border-strong);
    background: var(--app-card);
    box-shadow: var(--app-shadow-soft);
    position: relative;
    z-index: 1;
    pointer-events: auto;
}

.chat-input {
    width: 100%;
    border-radius: 1.2rem;
    border: none;
    padding: 0.4rem 0;
    background: transparent;
    color: var(--app-text);
}

.chat-input:focus {
    outline: none;
}

.send-button {
    border: none;
    border-radius: 999px;
    background: var(--app-accent-strong);
    color: #fff;
    font-weight: 600;
    padding: 0.5rem 0.85rem;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    position: relative;
    z-index: 2;
