    background: var(--app-border-strong);
}

.send-button.is-disabled {
    opacity: 0.55;
}

.chat-error {
    background: #fdecea;
    border: 1px solid #f5c2c0;
    color: #9b1c1c;
    padding: 0.75rem 1rem;
    border-radius: 0.9rem;
}

.chat-unauthorized {
    max-width: 520px;
    margin: 2.5rem auto;
    text-align: center;
    padding: 1.5rem;
    background: var(--app-card);
    border: 1px solid var(--app-border);
    border-radius: 1.2rem;
    box-shadow: var(--app-shadow-soft);
}

@media (max-width: 960px) {
    .chat-shell {
        padding-bottom: 0;
    }

    .chat-header,
    .chat-input-container {
        margin-left: -0.6rem;
        margin-right: -0.6rem;
        border-radius: 0;
    }

    .chat-panel-toggle {
        display: inline-flex;
    }

    .chat-input-container {
        grid-template-columns: 1fr;
        gap: 0.6rem;
        margin: 0 0 4.4rem;
    }

    .chat-messages {
        padding: 1rem 0.8rem 0.9rem;
    }

    .chat-message {
        max-width: 100%;
    }

    .effort-menu {
        left: 0;
        right: auto;
    }

    .chat-context {
        justify-content: flex-start;
    }
}

@media (min-width: 992px) {
    .chat-shell {
        padding-bottom: 0;
    }

    .chat-panel {
        left: 260px;
        width: min(320px, 30vw);
    }

    .chat-header,
    .chat-input-container {
        border-radius: 999px;
        margin: 1rem 1.8rem 0 0;
    }

    .chat-input-container {
        margin: 1rem 1.8rem 1rem 0;
        bottom: auto;
        left: auto;
        right: auto;
    }

    .chat-messages {
        padding-bottom: 1.6rem;
    }
